const tasks = ["مذاكرة", "رياضة", "قراءة"];
tasks.forEach((task, i) => {
  console.log((i + 1) + ". " + task);
});

const prices = [100, 250, 80];
const withTax = prices.map(p => p * 1.05);
console.log(withTax);  // [105, 262.5, 84]

const names = ["سالم", "ليلى"];
const greetings = names.map(n => "أهلًا " + n);
console.log(greetings);

const scores = [45, 88, 62, 95, 30];

const passed = scores.filter(s => s >= 60);
console.log("الناجحون:", passed);   // [88, 62, 95]

const firstHigh = scores.find(s => s > 90);
console.log("أول درجة فوق 90:", firstHigh); // 95

const ages = [17, 22, 30, 15];

console.log(ages.some(a => a >= 18));   // true يوجد بالغ
console.log(ages.every(a => a >= 18));  // false ليس الجميع

const total = ages.reduce((sum, age) => sum + age, 0);
console.log("المجموع:", total);        // 84
